SELECT [Item].No_ AS Article, [DDT_Picking Line].[Constant Variable Code] AS ColorCode, [DDT_Picking Line].[Assortment Code] AS AssortmentCode, Val([No_ of Pairs]) AS Pairs, Val([Quantity]) AS Boxes, [Item].[Trademark Code] AS TrademarkCode, [Item].[Line Code] AS LineCode, [Item].[Season Code] AS SeasonCode, [DDT_Picking Header].[Sell-to Customer No_] AS CustomerCode, [Customer].Name AS CustomerName, [DDT_Picking Header].No_ AS DocumentNR, [Salesperson_Purchaser].Code AS SalesPersonCode, [Salesperson_Purchaser].Name AS SalesPersonName
FROM ((([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type])) INNER JOIN Customer ON [DDT_Picking Header].[Sell-to Customer No_] = [Customer].No_) INNER JOIN Item ON [DDT_Picking Line].No_ = [Item].No_) INNER JOIN Salesperson_Purchaser ON [DDT_Picking Header].[Salesperson Code] = [Salesperson_Purchaser].Code
WHERE ((([DDT_Picking Header].No_)>=[Da DDT] And ([DDT_Picking Header].No_)<=[A DDT]) AND (([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Line].Type)=20));

